const input = $input.item.json;
const cust = input.customer_data || {};
const id = cust.identity || {};
const panApi = cust.pan_api_response || {};

const nameInput = (id.full_name || "").toLowerCase().trim();
const nameReg = (panApi.registered_name || "").toLowerCase().trim();
const addrProfile = (id.profile_address || "").toLowerCase().trim();
const addrUtility = (id.electricity_bill_address || "").toLowerCase().trim();

let status = "PROCEED";
let note = "Verified.";
let fraud = false;

if (nameReg !== "" && nameInput !== nameReg) {
  status = "REJECT";
  note = `FRAUD: ${id.full_name} vs ${panApi.registered_name}`;
  fraud = true;
} else if (addrProfile !== "" && addrUtility !== "" && !addrProfile.includes(addrUtility) && !addrUtility.includes(addrProfile)) {
  status = "REVIEW";
  note = "Address mismatch.";
}

return {
  ...input,
  identity_status: status,
  identity_note: note,
  fraudulent: fraud
};

const ai = $input.first().json;
let parsed = {};
try {
  let txt = ai.text || ai.output || JSON.stringify(ai);
  txt = txt.replace(/```json/gi, '').replace(/```/g, '').trim();
  parsed = JSON.parse(txt.substring(txt.indexOf('{'), txt.lastIndexOf('}') + 1));
} catch (e) { 
  parsed = { verdict: { final_disposition: "REJECT" } }; 
}

const data = $('Aggregate').first().json;
const disp = parsed.verdict?.final_disposition || "REJECT";

// THE TRUTH LOCK
const reason = (parsed.routing?.discrepancy_reason && parsed.routing.discrepancy_reason !== "") 
               ? parsed.routing.discrepancy_reason 
               : (data.identity_note || "");

return {
  customer_data: data.customer_data || data,
  customer_category: data.customer_category || data.segment,
  risk_metrics: {
    score: data.risk_score || 0,
    category: data.risk_category || "Unknown"
  },
  // NEW: KYC Scheduling data from LLM
  kyc_schedule: {
    interval_months: parsed.compliance?.kyc_interval_months || 12,
    review_rationale: parsed.compliance?.next_review_rationale || "Standard review cycle."
  },
  log_entry: `Verdict: ${disp}. Rationale: ${parsed.decision_rationale?.summary || "N/A"}`,
  task_type: (disp === "MANUAL_REVIEW" || disp === "REJECT") ? "Alert" : "None",
  call_agent: (disp === "MANUAL_REVIEW") ? "Template Agent" : "RM Banker",
  discrepancy_reason: reason 
};

const prev = $input.item.json;
const c = prev.customer_data || {};
const foir = (c.financial?.cibil?.total_emi || 0) / (c.data?.employment?.monthly_income || 1);

let mathDisp = (foir < 0.65) ? "APPROVE" : "REJECT";
let finalDisp = (prev.identity_status === "REJECT" || mathDisp === "REJECT") ? "REJECT" : (prev.identity_status === "REVIEW" ? "MANUAL_REVIEW" : "APPROVE");

// Risk Score: 100 is perfect, 0 is worst.
const riskScore = Math.max(0, Math.min(100, 100 - (foir * 100)));

// Risk Category for AI scheduling
let riskCategory = "Low";
if (riskScore < 40) riskCategory = "High";
else if (riskScore < 75) riskCategory = "Medium";

return { 
  ...prev, 
  segment: "Farmer", 
  foir: foir.toFixed(2), 
  disposition: finalDisp,
  risk_score: Math.round(riskScore),
  risk_category: riskCategory
};

const prev = $input.item.json;
const c = prev.customer_data || {};
const wealth = (c.financial?.wealth?.mutual_funds || 0) + (c.financial?.wealth?.insurance_val || 0);
const debt = c.financial?.cibil?.total_debt || 0; 
const emi = c.financial?.cibil?.total_emi || 0;
const inc = c.data?.employment?.monthly_income || 1;

const foir = emi / inc;
const wealthCover = debt > 0 ? (wealth / debt) : 100; 

let mathDisp = (foir < 0.8 && wealthCover > 2.0) ? "APPROVE" : "MANUAL_REVIEW";

let finalDisp = mathDisp;
if (prev.identity_status === "REJECT") finalDisp = "REJECT";

// Risk Score: Wealth cover (capped at 5x for scoring) + FOIR
const wealthComp = Math.min(5, wealthCover) * 20; // 5x cover = 100 points
const foirComp = Math.max(0, 100 - (foir * 100));
const riskScore = (wealthComp * 0.6) + (foirComp * 0.4);

let riskCategory = "Low";
if (riskScore < 40) riskCategory = "High";
else if (riskScore < 75) riskCategory = "Medium";

return { 
  ...prev, 
  segment: "HNI", 
  foir: foir.toFixed(2), 
  wealth_cover: wealthCover.toFixed(2), 
  disposition: finalDisp,
  risk_score: Math.round(riskScore),
  risk_category: riskCategory
};

const prev = $input.item.json;
const c = prev.customer_data || {};
const foir = (c.financial?.cibil?.total_emi || 0) / (c.data?.employment?.monthly_income || 1);

let mathDisp = (foir < 0.5) ? "APPROVE" : "REJECT";
let finalDisp = (prev.identity_status === "REJECT" || mathDisp === "REJECT") ? "REJECT" : (prev.identity_status === "REVIEW" ? "MANUAL_REVIEW" : "APPROVE");

// Risk Score: Stricter penalty for Mass segment
const riskScore = Math.max(0, Math.min(100, 100 - (foir * 150)));

let riskCategory = "Low";
if (riskScore < 40) riskCategory = "High";
else if (riskScore < 75) riskCategory = "Medium";

return { 
  ...prev, 
  segment: "Mass", 
  foir: foir.toFixed(2), 
  disposition: finalDisp,
  risk_score: Math.round(riskScore),
  risk_category: riskCategory
};
